import{_ as a,o as t,c as n,ae as s}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Journeys FAQs","description":"","frontmatter":{"title":"Journeys FAQs","slug":"journeys-faqs"},"headers":[],"relativePath":"marketer-hub/journeys-faqs.md","filePath":"marketer-hub/journeys-faqs.md"}'),o={name:"marketer-hub/journeys-faqs.md"};function i(r,e,l,p,d,h){return t(),n("div",null,[...e[0]||(e[0]=[s(`<p>The most frequently asked questions about Journeys.</p><h3 id="google-pagespeed-insights-seo-faqs" tabindex="-1">Google PageSpeed Insights &amp; SEO FAQs <a class="header-anchor" href="#google-pagespeed-insights-seo-faqs" aria-label="Permalink to &quot;Google PageSpeed Insights &amp; SEO FAQs&quot;">​</a></h3><details><summary>How do I reduce Cumulative Layout Shift (CLS)?</summary><h3 id="reducing-cumulative-layout-shift-cls" tabindex="-1">Reducing Cumulative Layout Shift (CLS) <a class="header-anchor" href="#reducing-cumulative-layout-shift-cls" aria-label="Permalink to &quot;Reducing Cumulative Layout Shift (CLS)&quot;">​</a></h3><p>Cumulative Layout Shift (CLS) is part of <a href="https://developers.google.com/speed/pagespeed/insights/" target="_blank" rel="noreferrer">Google&#39;s PageSpeed Insights</a> that measures the largest burst of layout shift scores for every unexpected layout shift that occurs during the entire lifespan of a page. The CLS score will vary based on the web page setup, the type of banner/interstitial, and page placement.</p><p>Google recommends reserving space for banners along with a placeholder option when the actual banner is not shown. Alternatively, this can be managed by using the CSS transform property in the Journeys editor.</p><p>Below are guidelines for reducing any negative contribution related to Journeys:</p><ol><li>Set the Page Placement of the banner/interstitial to the &quot;Customize Container (iFrame)&quot; option</li></ol><p><em>[Image: 954]</em>.png &quot;Screen Shot 2021-07-07 at 9.40.20 AM.png&quot;)</p><ol start="2"><li>Change the CSS based on the type of banner/interstitial:</li></ol><table tabindex="0"><thead><tr><th>Banner Type</th><th>Changes Needed</th><th>Example</th></tr></thead><tbody><tr><td>Inline banners of type - Full Page Interstitial Banner / Partial Interstitial/ Top Banner</td><td>- Add <code>body { transform: translate(0, );=&quot;&quot;&gt;</code> - Change value of top for <code>#branch-banner-iframe { top: -;=&quot;&quot;&gt;</code> Please note the value of top is negative.</td><td><code>#branch-banner-iframe { top: -456px; left: 0; right: 0; border: 0; height: 100vh; z-index: 99999; box-shadow: 0 0 5px rgba(0, 0, 0, .35); width: 1px; min-width: 100%; position: absolute; } body { transform: translate(0, 456px); }</code></td></tr><tr><td>Sticky banners of type - Full Page Interstitial Banner / Partial Interstitial/ Top Banner</td><td>- Add <code>body &gt; * { transform: translate(0, );=&quot;&quot;&gt;</code> - Change value of top for <code>#branch-banner-iframe { top: -;=&quot;&quot;&gt;</code> Please note the value of top is negative.</td><td><code>#branch-banner-iframe { top: -76px; left: 0; right: 0; border: 0; height: 100vh; z-index: 99999; box-shadow: 0 0 5px rgba(0, 0, 0, .35); width: 1px; min-width: 100%; position: absolute; } body &gt; * { transform: translate(0, 76px); }</code></td></tr></tbody></table><p>For additional details on CLS and Google&#39;s PageSpeed Insights tool visit the following pages:</p><ul><li><a href="https://web.dev/cls/" target="_blank" rel="noreferrer">Cumulative Layout Shift</a></li><li><a href="https://developers.google.com/speed/docs/insights/v5/about?hl=en-US&amp;utm_source=PSI&amp;utm_medium=incoming-link&amp;utm_campaign=PSI" target="_blank" rel="noreferrer">PageSpeed Insights</a></li><li><a href="https://web.dev/optimize-cls/" target="_blank" rel="noreferrer">Optimizing CLS</a></li></ul></details><details><summary>Do Branch Journeys get flagged by Google as a poor CX and hurt SEO?</summary><p>We&#39;ve observed in the past that there can be an impact when there&#39;s a full-page banner present on pages where a user is directly referred from Google, and, in the past, we&#39;ve advised against having these full takeover banners directly on these pages (via filtering traffic coming directly from Google on the Journeys setup or having a higher priority small banner targeted specifically for Search traffic). We&#39;ve got details on handling targeting for this <a href="./example-journeys.html#seo-friendly">here</a>.</p><p>There may be plans in the future to start using web vitals on all pages to adjust SEO scoring. The data for this would be collected from users who have opted into data sharing for optimization that use the Chrome mobile browser. The primary score we see impacted by Journeys is <strong>CLS, or Cumulative Layout Shift</strong>.</p><p>Here are <a href="./reducing-cumulative-layout-shift-cls.html">some tips on reducing the CLS score</a> here that may be helpful if you&#39;re looking to minimize any potential impact from this. As of yet we haven&#39;t seen or heard of actual significant impact to SEO based on these scores, but it definitely doesn&#39;t hurt to optimize somewhat just in case, especially if it doesn&#39;t affect the UX of your current banners much.</p><p>Additionally, please see our blog post on <a href="https://blog.branch.io/how-to-get-the-most-out-of-journeys-advanced-use-cases-part-1/" target="_blank" rel="noreferrer">How to Get the Most Out of Journeys</a>.</p></details><h3 id="customize-journeys-faqs" tabindex="-1">Customize Journeys FAQs <a class="header-anchor" href="#customize-journeys-faqs" aria-label="Permalink to &quot;Customize Journeys FAQs&quot;">​</a></h3><details><summary>Can I add two lines of text to my Journeys?</summary><p>You can add a second line of text to your Journey either before or after by adding it to the CSS element:</p><p><strong>Before</strong></p><p><code>branch-banner .branch-banner-description::before { display: block; content: &#39;Chat with other Fans&#39;; }</code></p><p><strong>After</strong></p><p><code>#branch-banner .branch-banner-description::after { display: block; content: &#39;Watch in Dark Mode&#39;; }</code></p></details><details><summary>Can I use a custom font for Journeys?</summary><ol><li>Go to Google Fonts and select a font. Find the embed URL for the font you selected.</li><li>Add to CSS EDITOR in your Journey template. For example:<br> @import url(&#39;<a href="https://fonts.googleapis.com/css2?family=Roboto&amp;display=swap&#39;)" target="_blank" rel="noreferrer">https://fonts.googleapis.com/css2?family=Roboto&amp;display=swap&#39;)</a>;</li></ol><p><strong>Note</strong>: The trailing semicolon on @import line is important. It&#39;s always good to have a fallback web font in case the google font fails to load.</p></details><details><summary>Can I localize the text of my Journeys?</summary><h3 id="client-side" tabindex="-1">Client-side <a class="header-anchor" href="#client-side" aria-label="Permalink to &quot;Client-side&quot;">​</a></h3><p>You can easily customize the Journey text dynamically client-side using setBranchViewData and by reading the browser&#39;s language.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var lang_code;</span></span>
<span class="line"><span>if (navigator.languages &amp;&amp; navigator.languages.length &gt; 0) {</span></span>
<span class="line"><span>    lang_code = navigator.languages[0];</span></span>
<span class="line"><span>} else if (navigator.language) {</span></span>
<span class="line"><span>    lang_code = navigator.language; // Change Journeys text if language is Spanish (ES) if (lang_code == &#39;es&#39;)</span></span>
<span class="line"><span>} </span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>    branch.setBranchViewData({</span></span>
<span class="line"><span>        data: {</span></span>
<span class="line"><span>            &quot;$journeys_title&quot;: &#39;Mi App&#39;,</span></span>
<span class="line"><span>            &quot;$journeys_description&quot;: &#39;Mi descripción&#39;,</span></span>
<span class="line"><span>            &quot;$journeys_button_get_has_app&quot;: &#39;Abrir&#39;,</span></span>
<span class="line"><span>            &quot;$journeys_button_get_no_app&quot;: &#39;Ver&#39;,</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    });</span></span>
<span class="line"><span>}</span></span></code></pre></div></details><details><summary>Can I prevent a Journey from showing with Javascript?</summary><p>You can prevent Journeys from showing on a certain page by inserting no_journeys with the value of true into the options during initialization.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script type=&quot;text/javascript&quot;&gt; // load the Branch SDK file branch.init(&#39;BRANCH_KEY&#39;, { &#39;no_journeys&#39;: true } ); &lt;/script&gt;</span></span></code></pre></div></details><details><summary>Can I close a Journey programmatically?</summary><p>Journeys include a close button the user can click, but you may want to close the Journey with a timeout, or via some other user interaction with your web app.<br> In this case, closing the Journey is very simple by calling:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>javascript branch.closeJourney(function(err) { console.log(err); });</span></span></code></pre></div></details><details><summary>Can I trigger a Journey to show?</summary><p>If you block or programmatically close a Journey via one of the calls above, then you can trigger a Journey to show by firing the following event:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Javascript branch.track(&#39;pageview&#39;);</span></span></code></pre></div><p><strong>Note</strong>: If a user has closed a Journey in the past, then firing the aforementioned event will not override a user&#39;s preference.</p></details><details><summary>Is there a way to disable Journeys animations?</summary><p>You can disable Journeys animations on a page by setting two flags - disable_entry_animation and disable_exit_animation - when you’re calling either init() or track() with Branch’s Web SDK.</p><p>Journeys animations can be disabled in order to reduce the amount of time it takes to load a Journey on a page. They can also be disabled in order to improve Journeys UX on single-page web apps, where Journeys animations can be jarring. When switching between multiple Journeys on a single-page web app, remember to use setBranchViewData() to change the link behind the CTA.</p><p>To disable animations during initialization, insert disable_entry_animation and/or disable_exit_animation, with values of true, into the options:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>javascript branch.init(‘BRANCH_KEY’, { ‘disable_entry_animation’ : true, ‘disable_exit_animation’ : true } );</span></span></code></pre></div><p>To disable animations using track(), insert disable_entry_animation and/or disable_exit_animation, with values of true, into the event metadata:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>javascript branch.track( ‘pageview’, {}, { ‘disable_entry_animation’ : true, ‘disable_exit_animation’ : true } )</span></span></code></pre></div></details><details><summary>Is there a way to set up a listener function to listen to events?</summary><p>You can easily listen to Journeys lifecycle events by registering listener functions like so:</p><p>javascript var listener = function(event, data) { console.log(event, data); } // Specify an event to listen for branch.addListener(&#39;willShowJourney&#39;, listener); // Listen for all events branch.addListener(listener);</p><table tabindex="0"><thead><tr><th>Listener Name</th><th>Description</th></tr></thead><tbody><tr><td>willShowJourney</td><td>Journey is about to be shown</td></tr><tr><td>didShowJourney</td><td>Journey&#39;s entrance animation has completed and it is being shown to the user</td></tr><tr><td>willNotShowJourney</td><td>Journey will not be shown and no other events will be emitted</td></tr><tr><td>didClickJourneyCTA</td><td>User clicked on Journey&#39;s CTA button</td></tr><tr><td>didClickJourneyClose</td><td>User clicked on Journey&#39;s close button</td></tr><tr><td>willCloseJourney</td><td>Journey close animation has started</td></tr><tr><td>didCloseJourney</td><td>Journey&#39;s close animation has completed and it is no longer visible to the user</td></tr></tbody></table></details><details><summary>What are the limitations of has\\_app?</summary><p>Several pieces of Journeys functionality rely on Branch’s understanding of whether an end-user has a customer’s app installed (indicated in Branch’s system using the has_app flag). For example, the CTA text on a Journey will only switch from “install” to “open” if Branch believes the app is installed on that user’s device.</p><p>Unfortunately, Branch does not - and cannot - know with 100% accuracy whether a given user actually has the app installed, since the operating systems (e.g. iOS, Android) do not make this information available to developers. We’ve developed our own methods for gleaning this information and while our methods are quite accurate, there are nevertheless opportunities for both false positives and false negatives. While these limitations shouldn’t discourage you from using features that rely on “has_app”, keep them in mind when designing your Journeys.</p><p>Several complicating factors are:</p><ul><li><strong>Install vs. Open</strong>: If a user installs an app but doesn’t open it, we won’t know that they have the app installed.</li><li><strong>Uninstalls</strong>: We won’t necessarily know if a user uninstalls an app, which could result in a false positive.</li><li><strong>Apple’s Intelligent Tracking Prevention</strong>: As a result of ITP, we’re less accurate on Safari on iOS than on all other browsers.</li><li><strong>Time to update</strong>: Latency in our system occasionally means that for a given user, in the moments (or minutes) following an install, Journeys may not know that the install has occurred.</li></ul></details><details><summary>How do I force a Journey to auto-open the app for users that have it installed?</summary><p>You can use Journeys to auto-open the app for users who have it installed by selecting the CTA in the template editor:</p><p>While the auto-open setting in the template editor will work on iOS Chrome and Android, there are some specific cases to be aware of:</p><ul><li><p>The Web SDK’s auto-open can cause unexpected user experiences if used on web pages inside webviews in your own app, so it’s best to avoid that if possible.</p></li><li><p>Auto-open will only work on Android Chrome from a link click; redirecting from a manually inserted URL will not auto-open the app.</p></li><li><p>Because auto-open is powered by URI schemes and these can lead to error messages on iOS Safari for users without your app, this is not enabled on iOS by default.</p><p>If you would like the app to open automatically on iOS Safari as well, you&#39;ll need to use a setting called <code>$uri_redirect_mode</code>. Since Branch has a massive pool of cookies tied to device identifiers, we know if your app is installed when the user clicks a link. We use this intelligence to determine when to use URI schemes. You can reach out to Support to enable this behavior across all your links, or set it just for Journeys in the web SDK:</p></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;script type=&quot;text/javascript&quot;&gt;</span></span>
<span class="line"><span>// load the Branch web lib</span></span>
<span class="line"><span>(function(b,r,a,n,c,h,_,s,d,k){if(!b[n]||!b[n]._q){for(;s&lt;_.length;)c(h,_[s++]);d=r.createElement(a);d.async=1;d.src=&quot;build.min.js&quot;;k=r.getElementsByTagName(a)[0];k.parentNode.insertBefore(d,k);b[n]=h}})(window,document,&quot;script&quot;,&quot;branch&quot;,function(b,r){b[r]=function(){b._q.push([r,arguments])}},{_q:[],_v:1},&quot;addListener applyCode banner closeBanner creditHistory credits data deepview deepviewCta first getCode init link logout redeem referrals removeListener sendSMS setBranchViewData setIdentity track validateCode&quot;.split(&quot; &quot;), 0);</span></span>
<span class="line"><span>// init Branch and pass in your preference to open the app</span></span>
<span class="line"><span>branch.init(&#39;BRANCH_KEY&#39;);</span></span>
<span class="line"><span>// Trigger your Journeys banner to use the correct redirect mode</span></span>
<span class="line"><span>branch.setBranchViewData({</span></span>
<span class="line"><span>        &#39;$uri_redirect_mode&#39;: 1</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre></div><p>Or, set it for individual templates by adding deep link data <code>$uri_redirect_mode:1</code>:</p><p>Read our <a href="https://blog.branch.io/making-uri-schemes-great-again-uri_redirect_mode/" target="_blank" rel="noreferrer">blog</a> to learn more about the challenges of URI schemes on iOS and the URI redirect mode feature.</p></details><details><summary>Can I pass link data to my Journeys banners so that when the app opens using the Journey, the SDK can read the data?</summary><p>Yes, this is possible, you can configure the link data and pass it to the link in the banner CTA using the setBranchViewData() function from the web SDK, please refer to the below link for more information on the same:</p><p><a href="./web-advanced-features.html#create-journeys-banner">Web Advanced Features</a></p></details><details><summary>How is A/B testing assigned out to users’ devices?</summary><p>Branch converts the user&#39;s browser fingerprint id (or a random id if not available) to a number between 1 and 100, and that number is used to pick a banner.</p><p>For example, if you have 2 banners (banner A given 20% weight and banner B given 80%) and the converted number Branch comes up with for the user is 15, then Branch would show the user banner A. This is because 15 is between 1 and 20. If the converted number is 55, then Branch would show banner B, because 55 is between 20 and 100.</p></details><h3 id="schedule-journeys-faqs" tabindex="-1">Schedule Journeys FAQs <a class="header-anchor" href="#schedule-journeys-faqs" aria-label="Permalink to &quot;Schedule Journeys FAQs&quot;">​</a></h3><details><summary>When does a Journey become active or stopped?</summary><p>There can be up to a 5-minute delay between a scheduled time and your Journey becoming active or stopped.</p></details><details><summary>How do I set an end date for a Journey with a recurring schedule?</summary><p>This is not supported by scheduling at this time. To do this, set a start and stop time for your Journey and add your repeat rules. When you want the Journey to stop for good, stop it from the action menu or go to Edit Schedule &gt; Delete.</p></details><details><summary>How do I set a delay time for a Journey banner to be displayed?</summary><p>A Journey can be delayed by logging a Pageview after a certain amount of time has elapsed in the Web SDK.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setTimeout(function () {</span></span>
<span class="line"><span>branch.closeJourney(function (err, data) {</span></span>
<span class="line"><span>if (err) {</span></span>
<span class="line"><span>console.log(err, data);</span></span>
<span class="line"><span>} else {</span></span>
<span class="line"><span>setTimeout(function () {</span></span>
<span class="line"><span>/*</span></span>
<span class="line"><span>This key/value pair is entirely arbitrary.</span></span>
<span class="line"><span>Its only purpose is to be found by a condition specified in the Branch dashboard.</span></span>
<span class="line"><span>*/</span></span>
<span class="line"><span>branch.track(&#39;pageview&#39;, {</span></span>
<span class="line"><span>&#39;delay&#39;: &#39;10&#39;</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span>}, 1000);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span>}, 10000);</span></span></code></pre></div></details><h3 id="referring-link-data-faqs" tabindex="-1">Referring link data FAQs <a class="header-anchor" href="#referring-link-data-faqs" aria-label="Permalink to &quot;Referring link data FAQs&quot;">​</a></h3><details><summary>Is there a way to preserve or discard referring link data?</summary><p>By default, when users arrive on a page running Journeys via a Branch Link and <code>make_new_link</code> is not set to <code>true</code>, then any interaction with the Journey (click/install/re-open) will be attributed to the referring Branch Link, rather than to the Journey. If <code>make_new_link</code> is set to <code>true</code>, the same events will be attributed to the Journey, instead.</p><p>This can help you collect data on how the referring links are contributing to app growth/engagement, even when users aren’t installing from those links directly. For example, if a user clicked a Branch Link on Facebook, landed on your website, and installed from a Journey, this would allow you to attribute the install to the link on Facebook. If the original link was also configured to deep link into your app, that deep link would be preserved, too.</p><p>Branch will pass the referring link into Journeys by default. In order to discard referring link data, include the <code>make_new_link</code> flag, with a value of <code>true</code>, into the options during initialization:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>branch.init( &#39;BRANCH_KEY&#39;,</span></span>
<span class="line"><span>    {</span></span>
<span class="line"><span>        &#39;make_new_link&#39; : true</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>);</span></span></code></pre></div></details><h3 id="journeys-analytics-faqs" tabindex="-1">Journeys analytics FAQs <a class="header-anchor" href="#journeys-analytics-faqs" aria-label="Permalink to &quot;Journeys analytics FAQs&quot;">​</a></h3><details><summary>Is there a way where I can view the analytics of Journeys created through the Web SDK?</summary><p>For Journeys created through the Web SDK ~branch_feature defaults to &quot;journeys&quot;. You can view the analytics by filtering Sources where feature equals journeys.</p></details><h3 id="troubleshooting-faqs" tabindex="-1">Troubleshooting FAQs <a class="header-anchor" href="#troubleshooting-faqs" aria-label="Permalink to &quot;Troubleshooting FAQs&quot;">​</a></h3><details><summary>Why does the “Has the app” installed filter not work in test mode?</summary><p>The filter &#39;Has the app install = true&#39; helps show the Journeys banner to only the user who already has the app installed.</p><p>In order to determine whether a user has the app installed, we use a flag called &#39;has_app&#39;. When the value of this flag is true, the above filter will show the Journeys banner to the user and will deep link into the app.</p><p>However, in order for this to work correctly, you need to be using the same Branch Keys in both your web page and your mobile application.</p><p>If you are using a test key in a staging environment, then the app installed in your device should also be using the same key as well.</p><p>Further, in test mode, we do not store real device identifiers in our database; due to this, the value of the &#39;has_app&#39; flag is not set correctly in test mode.</p><p>Therefore, in order to properly test the functioning of this filter, we recommend creating a Journeys banner on your live account.</p></details><details><summary>Why is my metadata filter not working on my webpage? The metadata is set as “abc”:”123”.</summary><p>Currently, we only support string key - value metadata pairs for the Journeys filter, and therefore, you will have to modify it as - <code>&quot;abc&quot;:&quot;123&quot;</code>.</p></details><details><summary>Why does my Journey still show “Get” after app install?</summary><p>Currently, when a user downloads an app by clicking a Journeys CTA button, our system will not update the user&#39;s has_app flag to true (indicating that the user has the app installed, until there is a &quot;strong match&quot; created).</p><p>In order for a strong match to be created, a user can:</p><ol><li>Go back to the page with the Journey</li><li>Re-click the CTA button and get directly deep-linked into the app (which creates a strong match)</li></ol><p>Our system will take about 5 - 10 mins to learn that the user has the app installed. After that period, when the same user refreshes the page with the Journey, the CTA text should change from &quot;GET&quot; to &quot;Open&quot;.</p><p>Also, when the app is frequently re-installed on the device, the flag that Branch uses to determine whether the app is installed on the device, has_app, goes in a faulty state.</p><p><strong>To force reset the has_app variable to change the Journey&#39;s banner CTA from &#39;Download&#39; to &#39;Open&#39;, please follow these steps:</strong></p><ol><li>Click on the Download button - this should redirect to the Play or App Store</li><li>Install the app</li><li>Return to the web page with the Journeys banner, which should still display the Download button</li><li>Tap on the Download button again - the app should open (once you update the entitlements file to include -alternate.app.link) and data specified in the Journeys configuration should be available to the app</li><li>Close and then re-open the web page with the Journeys banner - the banner should now have an &quot;Open&quot; button</li><li>Tap on the &quot;Open&quot; button</li></ol><p><em>It might take some time for the CTA button to update. It could be up to 30 minutes during peak hours.</em></p></details><details><summary>How can I check/retrieve the Branch Link behind any given banner?</summary><p>Load your Chrome desktop browser, enable developer tools by pressing ctrl+option+i, ensure the mobile view is selected, and then load the webpage with the banner. In the network tab of the developer tools, filter all requests by “branch” and inspect the “<a href="https://api2.branch.io/v1/pageview%E2%80%9D" target="_blank" rel="noreferrer">https://api2.branch.io/v1/pageview”</a> request. In the network response, search for “app.link” and you’ll find a reference to the actual link that was embedded behind the button (you can then copy this link and append “?debug=1” to inspect its data)</p></details>`,30)])])}const g=a(o,[["render",i]]);export{c as __pageData,g as default};
